import{_ as a,a as o}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as r,o as t,c as i,a2 as s}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Configuração e acesso por WebDAV","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/Safety/webdav-site-access.md","filePath":"pt-BR/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),d={name:"pt-BR/Safety/webdav-site-access.md"};function n(c,e,l,p,u,m){return t(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="configuracao-e-acesso-por-webdav" tabindex="-1">Configuração e acesso por WebDAV <a class="header-anchor" href="#configuracao-e-acesso-por-webdav" aria-label="Permalink to &quot;Configuração e acesso por WebDAV&quot;">​</a></h1><p>O ImgBed pode expor acesso por WebDAV para você revisar arquivos pelo explorador do sistema ou por um cliente compatível.</p><h2 id="quando-usar" tabindex="-1">Quando usar <a class="header-anchor" href="#quando-usar" aria-label="Permalink to &quot;Quando usar&quot;">​</a></h2><ul><li>Você quer ver arquivos pelo Windows ou macOS.</li><li>Usa um cliente WebDAV para organizar arquivos.</li><li>Precisa acessar arquivos fora do painel administrativo.</li></ul><h2 id="conectar-pelo-windows-11" tabindex="-1">Conectar pelo Windows 11 <a class="header-anchor" href="#conectar-pelo-windows-11" aria-label="Permalink to &quot;Conectar pelo Windows 11&quot;">​</a></h2><ol><li>Abra o Explorador de Arquivos.</li><li>Clique com o botão direito em <code>Este Computador</code>.</li><li>Escolha <code>Adicionar um local de rede</code>.</li><li>Informe a URL WebDAV.</li><li>Digite usuário e senha.</li><li>Confira se o conteúdo abre como uma pasta.</li></ol><p><img src="'+a+'" alt="Configuração WebDAV no Windows 11" loading="lazy"></p><p>Se a conexão estiver correta, o conteúdo aparece no Explorador.</p><p><img src="'+o+'" alt="WebDAV no Windows" loading="lazy"></p><h2 id="credenciais" tabindex="-1">Credenciais <a class="header-anchor" href="#credenciais" aria-label="Permalink to &quot;Credenciais&quot;">​</a></h2><p>Use as credenciais WebDAV configuradas no ImgBed. Para mais segurança, prefira uma conta com permissões limitadas em vez de uma conta principal compartilhada.</p><h2 id="se-nao-conectar" tabindex="-1">Se não conectar <a class="header-anchor" href="#se-nao-conectar" aria-label="Permalink to &quot;Se não conectar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Ponto</th><th>O que conferir</th></tr></thead><tbody><tr><td>URL</td><td>Se inclui <code>https://</code> e é o endereço WebDAV correto</td></tr><tr><td>Credenciais</td><td>Usuário e senha corretos</td></tr><tr><td>Permissões</td><td>Leitura e escrita no diretório alvo</td></tr><tr><td>Cliente</td><td>Se Windows ou cliente WebDAV não está bloqueando a conexão</td></tr></tbody></table><p>Se apenas a consulta de capacidade falhar, mas uploads funcionarem, o servidor WebDAV pode simplesmente não retornar informação de cota.</p>',14)])])}const _=r(d,[["render",n]]);export{f as __pageData,_ as default};
